import React, { useState, useEffect, useRef, Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { 
  OrbitControls, 
  useGLTF, 
  Environment, 
  PresentationControls,
  Stage,
  ContactShadows,
  Sparkles,
  Html
} from "@react-three/drei";
import { useParams, useNavigate } from 'react-router-dom';
import * as THREE from 'three';
import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';
import axios from 'axios';

function Model({ modelPath }) {
  const { scene } = useGLTF(modelPath);
  return <primitive object={scene} />;
}

// Preload the model
useGLTF.preload("http://localhost:3000/public/uploads/mustang.glb");

const PalmTree = ({ position, scale = 1 }) => {
  return (
    <group position={position} scale={scale}>
      <mesh castShadow position={[0, 2, 0]}>
        <cylinderGeometry args={[0.1, 0.2, 4, 6]} />
        <meshStandardMaterial color="#6f4e37" roughness={0.8} />
      </mesh>

      {[...Array(6)].map((_, i) => (
        <group
          key={i}
          rotation={[
            0.2,
            (Math.PI * 2 * i) / 6 + Math.random() * 0.5,
            Math.random() * 0.2 + 0.3
          ]}
          position={[0, 3.8, 0]}
        >
          <mesh castShadow>
            <coneGeometry args={[0.5, 2, 2]} />
            <meshStandardMaterial color="#2b9348" roughness={0.8} />
          </mesh>
        </group>
      ))}
    </group>
  );
};

const GameView = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [autoRotate, setAutoRotate] = useState(true);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const response = await axios.get(`http://localhost:3000/api/v1/products/${id}`);
        setProduct(response.data);
        setLoading(false);
      } catch (err) {
        console.error('Error loading product:', err);
        navigate('/');
      }
    };
    fetchProduct();
  }, [id, navigate]);

  if (loading) {
    return (
      <div className="fixed top-0 left-0 w-full h-full bg-black flex items-center justify-center text-white">
        Loading 3D viewer...
      </div>
    );
  }

  if (!product?.model3D) {
    return (
      <div className="fixed top-0 left-0 w-full h-full bg-black flex items-center justify-center text-white">
        3D model not available for this product
      </div>
    );
  }

  return (
    <div className="fixed top-0 left-0 w-full h-full bg-gradient-to-br from-zinc-900 to-black">
      {/* UI Overlay */}
      <div className="absolute top-0 left-0 w-full p-6 z-[60] flex justify-between items-start">
        <button
          onClick={() => navigate(-1)}
          className="bg-zinc-800/50 backdrop-blur-sm text-white px-6 py-3 rounded-xl 
            hover:bg-zinc-700/50 transition-all flex items-center gap-2"
        >
          <i className="fas fa-arrow-left"></i>
          Back to Product
        </button>

        {product && (
          <div className="bg-zinc-800/50 backdrop-blur-sm p-4 rounded-xl max-w-xs lg:max-w-md truncate">
            <h1 className="text-xl lg:text-2xl font-bold text-white truncate">{product.name}</h1>
            <p className="text-zinc-400 text-sm lg:text-base truncate">{product.collectionName}</p>
          </div>
        )}
      </div>

      <Canvas
        camera={{ 
          position: [8, 2, 10],
          fov: 50,
          near: 0.1,
          far: 1000
        }}
        className="w-full h-full bg-zinc-900"
      >
        <Suspense fallback={null}>
          <ambientLight intensity={0.5} />
          <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} />
          <pointLight position={[-10, -10, -10]} />

          <Model />

          <OrbitControls
            autoRotate
            autoRotateSpeed={1}
            enableZoom={true}
            enablePan={false}
            minPolarAngle={Math.PI / 4}
            maxPolarAngle={Math.PI / 2}
            minDistance={5}
            maxDistance={15}
            target={[0, -0.5, 0]}
          />
        </Suspense>
      </Canvas>

      {/* Control Bar */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-4 z-50">
        <button
          onClick={() => setAutoRotate(!autoRotate)}
          className="bg-zinc-800/50 backdrop-blur-sm text-white px-6 py-3 rounded-xl 
            hover:bg-zinc-700/50 transition-all flex items-center gap-2"
        >
          <i className={`fas fa-${autoRotate ? 'pause' : 'sync'}`}></i>
          {autoRotate ? 'Pause Rotation' : 'Auto Rotate'}
        </button>
      </div>
    </div>
  );
};

export default GameView;
